python3 << 'EOF'
import json
import re

with open('manifest.json', 'r') as f:
    manifest = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

errors = []

# Check release field
if 'release' not in manifest:
    errors.append("Missing 'release' field")
elif not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+$', manifest['release']):
    errors.append(f"Invalid release format: {manifest['release']}")
else:
    print(f"✓ release field valid: {manifest['release']}")

# Check components field
if 'components' not in manifest:
    errors.append("Missing 'components' field")
elif not isinstance(manifest['components'], list):
    errors.append("'components' must be an array")
elif len(manifest['components']) != 3:
    errors.append(f"'components' must have exactly 3 items, found {len(manifest['components'])}")
else:
    print(f"✓ components array has exactly 3 items")

    component_names = []
    for i, comp in enumerate(manifest['components']):
        if not isinstance(comp, dict):
            errors.append(f"Component {i} is not an object")
            continue

        # Check for extra properties
        extra_props = set(comp.keys()) - {'name', 'version'}
        if extra_props:
            errors.append(f"Component {i} has extra properties: {extra_props}")

        # Check name
        if 'name' not in comp:
            errors.append(f"Component {i} missing 'name'")
        elif not isinstance(comp['name'], str):
            errors.append(f"Component {i} 'name' must be string")
        elif len(comp['name']) == 0:
            errors.append(f"Component {i} 'name' cannot be empty")
        else:
            component_names.append(comp['name'])

        # Check version
        if 'version' not in comp:
            errors.append(f"Component {i} missing 'version'")
        elif not isinstance(comp['version'], str):
            errors.append(f"Component {i} 'version' must be string")
        elif not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', comp['version']):
            errors.append(f"Component {i} 'version' invalid format: {comp['version']}")
        else:
            print(f"✓ Component {i}: {comp['name']} {comp['version']}")

    # Check uniqueness
    if len(component_names) == len(set(component_names)):
        print(f"✓ All component names are unique")
    else:
        errors.append("Duplicate component names found")

# Check for extra top-level properties
extra_root = set(manifest.keys()) - {'release', 'components'}
if extra_root:
    errors.append(f"Extra root-level properties: {extra_root}")

if errors:
    print("\n❌ VALIDATION FAILED:")
    for error in errors:
        print(f"  - {error}")
    exit(1)
else:
    print("\n✓ manifest.json validates against schema.json")
EOF
